# Worked focus: http-py-message-delimitation-trailers — Reason about known lengths, HTTP/1.1 chunked delimitation, end of stream, and trailers without exposing framing details as semantics. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_body_streams_limits_2(compressed_bytes: int, decoded_bytes: int, maximum_decoded_bytes: int) -> dict[str, object]:
    assert all(isinstance(value, int) for value in (compressed_bytes, decoded_bytes, maximum_decoded_bytes))
    if compressed_bytes <= 0 or decoded_bytes < 0 or maximum_decoded_bytes <= 0:
        return {"accepted": False, "expansion_ratio": float("inf")}
    expansion_ratio = decoded_bytes / compressed_bytes
    return {"accepted": decoded_bytes <= maximum_decoded_bytes and expansion_ratio <= 100, "expansion_ratio": expansion_ratio}

